# ── Load NAS-Bench-201 benchmark data ──
# Try multiple possible locations
possible_paths = [
    Path("/workspace/naslib/naslib/data/nb201_all.pickle"),
    Path("./nb201_all.pickle"),
    Path("naslib/data/nb201_all.pickle"),
    Path("/workspace/naslib/nas-bench-201-v1_1-096897.pickle"),
]

data_path = None
for p in possible_paths:
    if p.exists():
        data_path = p
        break

# If still not found, try glob
if data_path is None:
    for p in Path("/workspace").rglob("nb201_all.pickle"):
        data_path = p
        break
if data_path is None:
    for p in Path("./").rglob("*.pickle"):
        if "nb201" in p.name.lower():
            data_path = p
            break
if data_path is None:
    for p in Path("./").rglob("*.pkl"):
        if "nb201" in p.name.lower():
            data_path = p
            break

if data_path is None:
    print(f"ERROR: Benchmark data not found. Searched:", flush=True)
    for p in possible_paths:
        print(f"  {p}: {'exists' if p.exists() else 'missing'}", flush=True)
    # Try listing workspace
    import subprocess
    try:
        result = subprocess.run(["find", "/workspace", "-name", "*.pickle", "-o", "-name", "*.pkl"],
                              capture_output=True, text=True, timeout=10)
        print(f"Found pickle files: {result.stdout}", flush=True)
    except:
        pass
    try:
        result = subprocess.run(["find", ".", "-name", "*.pickle", "-o", "-name", "*.pkl"],
                              capture_output=True, text=True, timeout=10)
        print(f"Found local pickle files: {result.stdout}", flush=True)
    except:
        pass
    sys.exit(1)
